// CORRECT: three-state DFS
const WHITE = 0, GRAY = 1, BLACK = 2;
const colors = new Map<string, number>();

function dfs(nodeId: string, path: string[]): boolean {
  const color = colors.get(nodeId) ?? WHITE;
  if (color === GRAY) return true; // back edge = cycle
  if (color === BLACK) return false; // cross-edge = safe

  colors.set(nodeId, GRAY); // mark entering
  const neighbors = graph.get(nodeId) ?? [];
  for (const neighbor of neighbors) {
    if (dfs(neighbor, [...path, nodeId])) return true;
  }
  colors.set(nodeId, BLACK); // mark completed
  return false;
}
